using System.ComponentModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable to run this app.");

IChatClient chatClient = new ChatClientBuilder(
        new OpenAIClient(apiKey).GetChatClient("gpt-4o-mini-2024-07-18"))
    .UseFunctionInvocation()
    .Build();

// --- Agent setup ---

var notebook = new Notebook();
var webSearch = new WebSearchTool();

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. When given a topic:
        1. Break it into 2-3 focused search queries
        2. Search the web for each query
        3. Take notes on key findings using add_note
        4. Review your notes with get_notes
        5. Provide a final comprehensive summary with key takeaways

        Always search and take notes before summarizing.
        """,
    name: "ResearchAgent",
    description: "Researches topics via web search and structured note-taking",
    tools:
    [
        AIFunctionFactory.Create(webSearch.SearchAsync, name: "search_web"),
        AIFunctionFactory.Create(notebook.AddNote, name: "add_note"),
        AIFunctionFactory.Create(notebook.GetNotes, name: "get_notes"),
    ]);

// --- Interactive loop ---

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided.");
    return;
}

Console.WriteLine($"\n🔬 Researching: {topic}\n");

var session = await agent.CreateSessionAsync();
var response = await agent.RunAsync(
    $"Research this topic thoroughly: {topic}",
    session,
    new ChatClientAgentRunOptions(new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
    }));

Console.WriteLine("\n📋 === Research Summary ===\n");
var summary = response.Messages
    .LastOrDefault(m => m.Role == ChatRole.Assistant && !string.IsNullOrWhiteSpace(m.Text));
Console.WriteLine(summary?.Text ?? "No summary generated.");
Console.WriteLine($"\n📝 Notes taken: {notebook.Count}");

// =============================================================================
// Tool implementations
// =============================================================================

/// <summary>
/// Simulated web search tool. Replace the body of <see cref="SearchAsync"/> with
/// a real provider (Bing Search API, Google Custom Search, etc.) for production use.
/// </summary>
sealed class WebSearchTool
{
    [Description("Search the web for information. Returns results with titles, snippets, and URLs.")]
    public Task<IReadOnlyList<SearchResult>> SearchAsync(
        [Description("The search query")] string query)
    {
        Console.WriteLine($"  🔍 Searching: \"{query}\"");

        var slug = Uri.EscapeDataString(query.ToLowerInvariant().Replace(' ', '-'));
        IReadOnlyList<SearchResult> results =
        [
            new($"Overview: {query}",
                $"A comprehensive overview of {query} covering fundamental concepts, "
                + "recent developments, and practical applications in the field.",
                $"https://encyclopedia.example.com/{slug}"),
            new($"{query} — Recent Advances (2025)",
                $"Latest research and breakthroughs in {query}. Studies from 2024–2025 "
                + "highlight significant progress in key areas including scalability and safety.",
                $"https://research.example.com/{slug}"),
            new($"Practical Guide to {query}",
                $"Expert analysis of {query} with best practices, common challenges, "
                + "and real-world case studies from industry leaders.",
                $"https://guide.example.com/{slug}"),
        ];

        return Task.FromResult(results);
    }
}

record SearchResult(string Title, string Snippet, string Url);

/// <summary>In-memory notebook that the agent uses to store and retrieve research notes.</summary>
sealed class Notebook
{
    private readonly List<Note> _notes = [];
    public int Count => _notes.Count;

    [Description("Save a research note for later reference.")]
    public string AddNote(
        [Description("Short title for the note")] string title,
        [Description("Detailed content of the note")] string content)
    {
        _notes.Add(new Note(title, content, DateTime.UtcNow));
        Console.WriteLine($"  📝 Note added: \"{title}\"");
        return $"Note '{title}' saved successfully.";
    }

    [Description("Retrieve all saved research notes.")]
    public IReadOnlyList<Note> GetNotes()
    {
        Console.WriteLine($"  📖 Retrieved {_notes.Count} note(s)");
        return _notes.AsReadOnly();
    }
}

